import React, { useState, useEffect, useRef } from 'react';
import { ChevronLeft, ChevronRight, RefreshCw } from 'lucide-react';
import { getLocalImage } from '../services/imageStore';

const FallbackPanel = ({ narrative }) => (
  <div className="w-full h-full flex items-center justify-center bg-gray-900 border-2 border-dashed border-gray-600 p-8">
    <div className="text-center">
      <p className="text-gray-400 text-lg italic mb-4">[ Image not available offline ]</p>
      <p className="text-lg text-white font-sans">{narrative}</p>
    </div>
  </div>
);



export default function StoryView({ storyData, isLoading, onSync }) {
  const { panels = [], loadingMessage } = storyData;
  const [displayPanels, setDisplayPanels] = useState([]);
  const [currentPage, setCurrentPage] = useState(1);
  const scrollContainerRef = useRef(null);
  const totalPages = displayPanels.length;

  useEffect(() => {
    let isMounted = true;
    const generateLocalUrls = async () => {
      if (!panels) return;
      const panelsWithLocalUrls = await Promise.all(
        panels.map(async (panel) => {
          const localUrl = await getLocalImage(panel.imageUrl);
          return { ...panel, localImageUrl: localUrl };
        })
      );
      if (isMounted) {
        setDisplayPanels(panelsWithLocalUrls);
      }
    };
    generateLocalUrls();
    return () => { isMounted = false; };
  }, [panels]);


  useEffect(() => {
    const container = scrollContainerRef.current;
    if (!container) return;
    const handleScroll = () => {
      const pageIndex = Math.round(container.scrollLeft / container.clientWidth);
      if (pageIndex + 1 !== currentPage) setCurrentPage(pageIndex + 1);
    };
    let scrollTimeout;
    const debouncedScrollHandler = () => {
      clearTimeout(scrollTimeout);
      scrollTimeout = setTimeout(handleScroll, 150);
    };
    container.addEventListener('scroll', debouncedScrollHandler);
    return () => container.removeEventListener('scroll', debouncedScrollHandler);
  }, [currentPage]);

  const goToPage = (pageNumber) => {
    const container = scrollContainerRef.current;
    if (container) {
      container.scrollTo({
        left: (pageNumber - 1) * container.clientWidth,
        behavior: 'smooth',
      });
      setCurrentPage(pageNumber);
    }
  };

  const renderContent = () => {
    if (totalPages === 0 && !isLoading) {
      return (
        <div className="text-center p-10 flex flex-col items-center justify-center h-full">
            <h2 className="text-xl text-white">Your story awaits.</h2>
            <p className="text-gray-400">Sync with your entries to begin.</p>
        </div>
      );
    }
    return (
      <div className="h-full w-full relative">
        <div ref={scrollContainerRef} className="w-full h-full flex overflow-x-auto snap-x snap-mandatory scroll-smooth">
          {displayPanels.map((panel) => (
            // --- NEW --- Modified layout for the minimalist look
            <div key={panel.panelId} className="w-full h-full flex-shrink-0 snap-center flex flex-col items-center justify-center p-4">
              
              <div className="w-full max-w-md flex-1 flex flex-col items-center justify-center">
                <div className="w-full flex-1 flex items-center justify-center overflow-hidden">
                    <img 
                        src={panel.localImageUrl || panel.imageUrl} 
                        alt={panel.narrative} 
                        className="max-w-full max-h-full object-contain" // Ensures image is letterboxed
                        onError={(e) => { e.target.style.display = 'none'; e.target.nextSibling.style.display = 'flex'; }}
                    />
                    <div style={{display: 'none'}} className="w-full h-full items-center justify-center">
                        <FallbackPanel narrative={panel.narrative} />
                    </div>
                </div>
              </div>

              <div className="w-full max-w-md p-6 text-center flex-shrink-0">
                <p className="text-lg text-white font-manga">{panel.narrative}</p>
              </div>

            </div>
          ))}
        </div>
        {currentPage > 1 && <button onClick={() => goToPage(currentPage - 1)} className="absolute left-4 top-1/2 -translate-y-1/2 p-2 bg-black/50 rounded-full z-10"><ChevronLeft/></button>}
        {currentPage < totalPages && <button onClick={() => goToPage(currentPage + 1)} className="absolute right-4 top-1/2 -translate-y-1/2 p-2 bg-black/50 rounded-full z-10"><ChevronRight/></button>}
      </div>
    );
  };

  return (
    <div className="h-[calc(100vh-4rem)] w-screen flex flex-col bg-black text-white">
      <div className="flex-shrink-0">
        <div className="flex justify-between items-center px-4 py-2">
            <h2 className="text-lg font-bold text-center text-purple-400">
            Page: {currentPage} / {totalPages || '?'}
            </h2>
            <button onClick={onSync} disabled={isLoading} className="flex items-center gap-2 bg-purple-600 text-white px-4 py-2 rounded-lg disabled:bg-gray-500 hover:bg-purple-700 transition-colors">
            <RefreshCw size={18} className={isLoading ? 'animate-spin' : ''} />
            {isLoading ? 'Syncing...' : 'Sync New Entries'}
            </button>
        </div>

        {loadingMessage && (
            <div className={`text-center py-2 text-sm transition-all ${loadingMessage.toLowerCase().includes('error') ? 'bg-red-900/50 text-red-200' : 'bg-purple-900/50 text-purple-200'}`}>
                {loadingMessage}
            </div>
        )}
      </div>
      
      <div className="flex-1 overflow-hidden">
        {renderContent()}
      </div>
    </div>
  );
}
